import random
import time
from typing import Callable

import matplotlib.pyplot as plt
from tqdm import tqdm
from pyroaring import BitMap

from grqe.sets import BucketRangeSet

type Set = BucketRangeSet


def create_arbitrary_bitmap(corpus_size: int, load: float) -> BitMap:
    bm = BitMap()
    for i in range(corpus_size):
        if random.random() < load:
            bm.add(i)
    return bm


def create_arbitrary_set(corpus_size: int, load: float, buckets: int) -> Set:
    buckets = {
        1 + i: create_arbitrary_bitmap(corpus_size, load)
        for i in range(buckets)
    }
    return BucketRangeSet(buckets)


BUCKETS = [2, 4, 6]
CORPUS_SIZES = sorted([int(p * 10 ** e) for p in [1, 5] for e in [6, 8]])
LOAD_FACTORS = [0.1, 0.2, 0.5, 0.8]

TRIALS = 10


def do_measure(operation: Callable[[Set, Set], Set], corpus_size: int, load: float, buckets: int) -> float:
    sets = [create_arbitrary_set(corpus_size, load, buckets) for _ in range(TRIALS)]

    before = time.perf_counter()
    for a in sets:
        for b in sets:
            operation(a, b)
    after = time.perf_counter()
    return (after - before) / (TRIALS * TRIALS)


def measure_coefficients(operation: Callable[[Set, Set], Set], op_name: str):
    total = len(BUCKETS) * len(CORPUS_SIZES) * len(LOAD_FACTORS)

    with tqdm(total=total, desc='Measuring runtime...') as pbar:
        Data = []

        for no_buckets in BUCKETS:
            for corpus_size in CORPUS_SIZES:
                for load_factor in LOAD_FACTORS:
                    measurement = do_measure(operation, corpus_size, load_factor, no_buckets)
                    Data.append((corpus_size, load_factor, no_buckets, measurement))

                    pbar.update(1)

        print(op_name)
        print(Data)


#measure_coefficients(BucketRangeSet.conjunction, 'conjunction')
#measure_coefficients(BucketRangeSet.disjunction, 'disjunction')
#measure_coefficients(BucketRangeSet.join, 'join')



def function(X, cs_factor, lf_factor, nb_factor):
    (corpus_size, load_factor, no_buckets) = X
    return (cs_factor * corpus_size) + (1 / lf_factor * load_factor) + (nb_factor * no_buckets)


def visualize(data, operator_name):
    CS_COLORS = ['lime', 'green', 'orange', 'red']


    #plt.yscale('log')
    for cs_color, expected_corpus_size in enumerate(CORPUS_SIZES):
        for bucket in BUCKETS:
            Xs = []
            Ys = []
            Y2s = []

            for (corpus_size, load_factor, no_buckets, measurement) in data:
                if expected_corpus_size == corpus_size and no_buckets == bucket:
                    Xs.append(load_factor)
                    Ys.append(measurement)

            plt.plot(Xs, Ys, color=CS_COLORS[cs_color])
#            plt.plot(Xs, Y2s, '--', color='gray')
    plt.title(operator_name)
    plt.show()


